import React, { useEffect, useState } from 'react';
import api from '../../services/api';

// ── Constantes ────────────────────────────────────────────────────────────────
const EMPTY_FORM = {
  titleFr: '', titleEn: '',
  descriptionFr: '', descriptionEn: '',
  location: '',
  typeFr: 'CDI', typeEn: 'Full-time',
  experienceFr: '', experienceEn: '',
  departmentFr: '', departmentEn: '',
  tags: '',
  active: true,
};

// ── Sous-composants ───────────────────────────────────────────────────────────

function Badge({ active }) {
  return (
    <span className={`status-badge ${active ? 'status-new' : 'status-completed'}`}>
      {active ? 'Publiée' : 'Archivée'}
    </span>
  );
}

function IconPlus() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
      <line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" />
    </svg>
  );
}

function IconEdit() {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" />
      <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" />
    </svg>
  );
}

function IconArchive() {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="21 8 21 21 3 21 3 8" />
      <rect x="1" y="3" width="22" height="5" />
      <line x1="10" y1="12" x2="14" y2="12" />
    </svg>
  );
}

function IconRestore() {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="1 4 1 10 7 10" />
      <path d="M3.51 15a9 9 0 1 0 .49-3.51" />
    </svg>
  );
}

// ── Formulaire (création + édition) ──────────────────────────────────────────

function OfferForm({ initial, onSave, onCancel, loading }) {
  const [form, setForm] = useState(initial || EMPTY_FORM);
  const isEdit = !!initial?.id;

  const set = (field) => (e) =>
    setForm((f) => ({ ...f, [field]: e.target.type === 'checkbox' ? e.target.checked : e.target.value }));

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(form);
  };

  const inputStyle = {
    width: '100%', padding: '8px 12px', borderRadius: '10px',
    border: '1px solid hsl(var(--border))',
    background: 'hsl(var(--muted) / 0.4)',
    color: 'hsl(var(--foreground))',
    fontSize: '0.875rem', outline: 'none',
    transition: 'border-color 0.2s',
    boxSizing: 'border-box',
  };

  const labelStyle = {
    display: 'block', fontSize: '0.75rem', fontWeight: 600,
    color: 'hsl(var(--muted-foreground))', marginBottom: '4px',
    textTransform: 'uppercase', letterSpacing: '0.04em',
  };

  const rowStyle = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' };

  const sectionTitle = (title) => (
    <div style={{
      display: 'flex', alignItems: 'center', gap: '8px',
      margin: '20px 0 12px', color: 'hsl(var(--muted-foreground))',
      fontSize: '0.75rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.06em',
    }}>
      <div style={{ flex: 1, height: 1, background: 'hsl(var(--border))' }} />
      {title}
      <div style={{ flex: 1, height: 1, background: 'hsl(var(--border))' }} />
    </div>
  );

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 100,
      background: 'hsl(220 25% 12% / 0.6)',
      backdropFilter: 'blur(4px)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      padding: '24px',
    }}>
      <div className="premium-card" style={{
        width: '100%', maxWidth: '720px', maxHeight: '90vh',
        overflowY: 'auto', padding: '32px',
      }}>
        {/* En-tête */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h2 style={{ margin: 0, fontSize: '1.25rem', fontWeight: 700, color: 'hsl(var(--foreground))' }}>
              {isEdit ? 'Modifier l\'offre' : 'Nouvelle offre d\'emploi'}
            </h2>
            <p style={{ margin: '4px 0 0', fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
              {isEdit ? 'Les modifications sont publiées immédiatement.' : 'L\'offre sera visible sur le site web dès publication.'}
            </p>
          </div>
          <button onClick={onCancel} style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: 'hsl(var(--muted-foreground))', fontSize: '1.25rem', padding: '4px 8px',
          }}>✕</button>
        </div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>

          {sectionTitle('Titre du poste')}
          <div style={rowStyle}>
            <div>
              <label style={labelStyle}>🇫🇷 Français *</label>
              <input style={inputStyle} value={form.titleFr} onChange={set('titleFr')}
                placeholder="ex: Développeur Java Senior" required />
            </div>
            <div>
              <label style={labelStyle}>🇬🇧 English *</label>
              <input style={inputStyle} value={form.titleEn} onChange={set('titleEn')}
                placeholder="ex: Senior Java Developer" required />
            </div>
          </div>

          {sectionTitle('Description courte (liste des offres)')}
          <div style={rowStyle}>
            <div>
              <label style={labelStyle}>🇫🇷 Français *</label>
              <textarea style={{ ...inputStyle, resize: 'vertical', minHeight: '80px' }}
                value={form.descriptionFr} onChange={set('descriptionFr')}
                placeholder="Courte description visible sur la page Careers…" required />
            </div>
            <div>
              <label style={labelStyle}>🇬🇧 English *</label>
              <textarea style={{ ...inputStyle, resize: 'vertical', minHeight: '80px' }}
                value={form.descriptionEn} onChange={set('descriptionEn')}
                placeholder="Short description shown on the Careers page…" required />
            </div>
          </div>

          {sectionTitle('Informations pratiques')}
          <div style={rowStyle}>
            <div>
              <label style={labelStyle}>📍 Localisation *</label>
              <input style={inputStyle} value={form.location} onChange={set('location')}
                placeholder="ex: 🇹🇳 Tunis, Tunisia" required />
            </div>
            <div>
              <label style={labelStyle}>🏷️ Tags (virgules)</label>
              <input style={inputStyle} value={form.tags} onChange={set('tags')}
                placeholder="ex: Java,Spring Boot,Docker" />
            </div>
          </div>

          <div style={rowStyle}>
            <div style={rowStyle}>
              <div>
                <label style={labelStyle}>Type (FR)</label>
                <input style={inputStyle} value={form.typeFr} onChange={set('typeFr')} placeholder="CDI" />
              </div>
              <div>
                <label style={labelStyle}>Type (EN)</label>
                <input style={inputStyle} value={form.typeEn} onChange={set('typeEn')} placeholder="Full-time" />
              </div>
            </div>
            <div style={rowStyle}>
              <div>
                <label style={labelStyle}>Expérience (FR)</label>
                <input style={inputStyle} value={form.experienceFr} onChange={set('experienceFr')} placeholder="3–5 ans" />
              </div>
              <div>
                <label style={labelStyle}>Expérience (EN)</label>
                <input style={inputStyle} value={form.experienceEn} onChange={set('experienceEn')} placeholder="3–5 years" />
              </div>
            </div>
          </div>

          <div style={rowStyle}>
            <div>
              <label style={labelStyle}>Département (FR)</label>
              <input style={inputStyle} value={form.departmentFr} onChange={set('departmentFr')} placeholder="Ingénierie" />
            </div>
            <div>
              <label style={labelStyle}>Département (EN)</label>
              <input style={inputStyle} value={form.departmentEn} onChange={set('departmentEn')} placeholder="Engineering" />
            </div>
          </div>

          {sectionTitle('Publication')}
          <label style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
            <input type="checkbox" checked={form.active} onChange={set('active')}
              style={{ width: '16px', height: '16px', accentColor: 'hsl(var(--primary))' }} />
            <span style={{ fontSize: '0.875rem', color: 'hsl(var(--foreground))' }}>
              Publier sur le site web immédiatement
            </span>
          </label>

          {/* Actions */}
          <div style={{ display: 'flex', gap: '10px', marginTop: '8px', justifyContent: 'flex-end' }}>
            <button type="button" onClick={onCancel} style={{
              padding: '9px 20px', borderRadius: '9999px',
              border: '1px solid hsl(var(--border))',
              background: 'none', color: 'hsl(var(--foreground))',
              fontSize: '0.875rem', fontWeight: 500, cursor: 'pointer',
            }}>
              Annuler
            </button>
            <button type="submit" disabled={loading} style={{
              padding: '9px 24px', borderRadius: '9999px', border: 'none',
              background: loading ? 'hsl(var(--muted))' : 'hsl(var(--foreground))',
              color: loading ? 'hsl(var(--muted-foreground))' : 'hsl(var(--card))',
              fontSize: '0.875rem', fontWeight: 600, cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'all 0.2s',
            }}>
              {loading ? 'Enregistrement…' : isEdit ? '✓ Mettre à jour' : '✓ Publier l\'offre'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ── Carte d'offre ─────────────────────────────────────────────────────────────

function OfferCard({ offer, onEdit, onToggle }) {
  const tags = offer.tagList ?? [];

  return (
    <div className="premium-card" style={{ padding: '20px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '8px' }}>
        <div style={{ flex: 1 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap', marginBottom: '2px' }}>
            <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700, color: 'hsl(var(--foreground))' }}>
              {offer.titleFr}
            </h3>
            <Badge active={offer.active} />
          </div>
          <p style={{ margin: 0, fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
            {offer.titleEn}
          </p>
        </div>
        {/* Actions */}
        <div style={{ display: 'flex', gap: '6px', flexShrink: 0 }}>
          <button
            onClick={() => onEdit(offer)}
            title="Modifier"
            style={{
              display: 'flex', alignItems: 'center', gap: '5px',
              padding: '6px 12px', borderRadius: '9999px',
              border: '1px solid hsl(var(--border))',
              background: 'hsl(var(--card))',
              color: 'hsl(var(--foreground))',
              fontSize: '0.75rem', fontWeight: 500, cursor: 'pointer',
            }}
          >
            <IconEdit /> Modifier
          </button>
          <button
            onClick={() => onToggle(offer)}
            title={offer.active ? 'Archiver' : 'Republier'}
            style={{
              display: 'flex', alignItems: 'center', gap: '5px',
              padding: '6px 12px', borderRadius: '9999px',
              border: '1px solid hsl(var(--border))',
              background: 'hsl(var(--card))',
              color: offer.active ? 'hsl(var(--destructive))' : 'hsl(var(--status-new))',
              fontSize: '0.75rem', fontWeight: 500, cursor: 'pointer',
            }}
          >
            {offer.active ? <><IconArchive /> Archiver</> : <><IconRestore /> Republier</>}
          </button>
        </div>
      </div>

      {/* Méta */}
      <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
        {offer.location && (
          <span style={{ fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
            📍 {offer.location}
          </span>
        )}
        {offer.typeEn && (
          <span style={{ fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
            💼 {offer.typeFr || offer.typeEn}
          </span>
        )}
        {offer.experienceEn && (
          <span style={{ fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
            ⏱️ {offer.experienceFr || offer.experienceEn}
          </span>
        )}
        {offer.departmentEn && (
          <span style={{ fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))' }}>
            🏢 {offer.departmentFr || offer.departmentEn}
          </span>
        )}
      </div>

      {/* Description */}
      {offer.descriptionFr && (
        <p style={{
          margin: 0, fontSize: '0.85rem', color: 'hsl(var(--muted-foreground))',
          lineHeight: 1.6,
          display: '-webkit-box', WebkitLineClamp: 2,
          WebkitBoxOrient: 'vertical', overflow: 'hidden',
        }}>
          {offer.descriptionFr}
        </p>
      )}

      {/* Tags */}
      {tags.length > 0 && (
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
          {tags.map((tag) => (
            <span key={tag} style={{
              padding: '3px 10px', borderRadius: '9999px',
              background: 'hsl(var(--muted))',
              color: 'hsl(var(--muted-foreground))',
              fontSize: '0.72rem', fontWeight: 500,
            }}>
              {tag}
            </span>
          ))}
        </div>
      )}

      {/* Date */}
      <p style={{ margin: 0, fontSize: '0.72rem', color: 'hsl(var(--border))', textAlign: 'right' }}>
        Créée le {new Date(offer.createdAt).toLocaleDateString('fr-FR', {
          day: 'numeric', month: 'long', year: 'numeric',
        })}
      </p>
    </div>
  );
}

// ── Page principale ───────────────────────────────────────────────────────────

export default function JobOffers() {
  const [offers, setOffers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingOffer, setEditingOffer] = useState(null);
  const [filter, setFilter] = useState('all'); // 'all' | 'active' | 'archived'
  const [search, setSearch] = useState('');

  // ── Fetch ──────────────────────────────────────────────────────────────────
  const fetchOffers = async () => {
    try {
      const res = await api.get('/job-offers/all');
      setOffers(res.data);
    } catch {
      setError('Impossible de charger les offres. Vérifiez que Spring Boot est démarré.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchOffers(); }, []);

  // ── Notifications ──────────────────────────────────────────────────────────
  const notify = (msg) => {
    setSuccess(msg);
    setTimeout(() => setSuccess(''), 3500);
  };

  // ── Créer / Modifier ───────────────────────────────────────────────────────
  const handleSave = async (form) => {
    setSaving(true);
    setError('');
    try {
      if (editingOffer) {
        await api.put(`/job-offers/${editingOffer.id}`, form);
        notify('✓ Offre mise à jour avec succès.');
      } else {
        await api.post('/job-offers', form);
        notify('✓ Offre publiée ! Elle est maintenant visible sur le site web.');
      }
      setShowForm(false);
      setEditingOffer(null);
      fetchOffers();
    } catch {
      setError("Erreur lors de l'enregistrement. Vérifiez les champs et réessayez.");
    } finally {
      setSaving(false);
    }
  };

  // ── Archiver / Republier ───────────────────────────────────────────────────
  const handleToggle = async (offer) => {
    const action = offer.active ? 'archiver' : 'republier';
    if (!window.confirm(`Voulez-vous ${action} cette offre ?`)) return;
    try {
      if (offer.active) {
        // DELETE → archive côté Spring Boot (active=false)
        await api.delete(`/job-offers/${offer.id}`);
        notify('Offre archivée. Elle n\'est plus visible sur le site web.');
      } else {
        // PUT avec active=true pour republier
        await api.put(`/job-offers/${offer.id}`, { ...offer, active: true });
        notify('✓ Offre republiée ! Elle est de nouveau visible sur le site web.');
      }
      fetchOffers();
    } catch {
      setError('Erreur lors de la mise à jour du statut.');
    }
  };

  // ── Ouvrir formulaire ──────────────────────────────────────────────────────
  const openCreate = () => { setEditingOffer(null); setShowForm(true); };
  const openEdit = (offer) => { setEditingOffer(offer); setShowForm(true); };
  const closeForm = () => { setShowForm(false); setEditingOffer(null); };

  // ── Filtrage ───────────────────────────────────────────────────────────────
  const filtered = offers
    .filter((o) => {
      if (filter === 'active') return o.active;
      if (filter === 'archived') return !o.active;
      return true;
    })
    .filter((o) => {
      if (!search) return true;
      const q = search.toLowerCase();
      return (
        o.titleFr?.toLowerCase().includes(q) ||
        o.titleEn?.toLowerCase().includes(q) ||
        o.location?.toLowerCase().includes(q) ||
        o.tags?.toLowerCase().includes(q)
      );
    });

  const activeCount = offers.filter((o) => o.active).length;
  const archivedCount = offers.filter((o) => !o.active).length;

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>

      {/* ── Barre d'action ── */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '12px', flexWrap: 'wrap' }}>
        <p style={{ fontSize: '0.875rem', color: 'hsl(var(--muted-foreground))', margin: 0 }}>
          Gérez les offres publiées sur le site web Tritux.
        </p>
        <button
          onClick={openCreate}
          style={{
            display: 'inline-flex', alignItems: 'center', gap: '6px',
            padding: '8px 18px', borderRadius: '9999px', border: 'none',
            background: 'hsl(var(--foreground))',
            color: 'hsl(var(--card))',
            fontSize: '0.875rem', fontWeight: 600, cursor: 'pointer',
          }}
        >
          <IconPlus /> Nouvelle offre
        </button>
      </div>

      {/* ── Notifications ── */}
      {success && (
        <div style={{
          padding: '12px 16px', borderRadius: '12px',
          background: 'hsl(var(--status-new) / 0.1)',
          border: '1px solid hsl(var(--status-new) / 0.3)',
          color: 'hsl(var(--status-new))',
          fontSize: '0.875rem', fontWeight: 500,
        }}>
          {success}
        </div>
      )}
      {error && (
        <div style={{
          padding: '12px 16px', borderRadius: '12px',
          background: 'hsl(var(--destructive) / 0.1)',
          border: '1px solid hsl(var(--destructive) / 0.3)',
          color: 'hsl(var(--destructive))',
          fontSize: '0.875rem',
        }}>
          {error}
        </div>
      )}

      {/* ── Statistiques rapides ── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>
        {[
          { label: 'Total', value: offers.length, icon: '📋' },
          { label: 'Publiées', value: activeCount, icon: '🟢' },
          { label: 'Archivées', value: archivedCount, icon: '📦' },
        ].map(({ label, value, icon }) => (
          <div key={label} className="premium-card" style={{ padding: '16px 20px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontSize: '0.8rem', color: 'hsl(var(--muted-foreground))', fontWeight: 500 }}>{label}</span>
              <span style={{ fontSize: '1.1rem' }}>{icon}</span>
            </div>
            <p style={{ margin: '8px 0 0', fontSize: '1.75rem', fontWeight: 700, color: 'hsl(var(--foreground))' }}>
              {value}
            </p>
          </div>
        ))}
      </div>

      {/* ── Filtres + Recherche ── */}
      <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', alignItems: 'center' }}>
        {/* Tabs filtre */}
        <div style={{
          display: 'flex', gap: '4px', padding: '4px',
          background: 'hsl(var(--muted))', borderRadius: '9999px',
        }}>
          {[
            { key: 'all', label: `Toutes (${offers.length})` },
            { key: 'active', label: `Publiées (${activeCount})` },
            { key: 'archived', label: `Archivées (${archivedCount})` },
          ].map(({ key, label }) => (
            <button key={key} onClick={() => setFilter(key)} style={{
              padding: '6px 14px', borderRadius: '9999px', border: 'none',
              background: filter === key ? 'hsl(var(--card))' : 'transparent',
              color: filter === key ? 'hsl(var(--foreground))' : 'hsl(var(--muted-foreground))',
              fontWeight: filter === key ? 600 : 400,
              fontSize: '0.8rem', cursor: 'pointer',
              boxShadow: filter === key ? 'var(--shadow-sm)' : 'none',
              transition: 'all 0.2s',
            }}>
              {label}
            </button>
          ))}
        </div>

        {/* Recherche */}
        <input
          value={search} onChange={(e) => setSearch(e.target.value)}
          placeholder="Rechercher par titre, localisation, tag…"
          style={{
            flex: 1, minWidth: '220px', padding: '8px 14px',
            borderRadius: '9999px', border: '1px solid hsl(var(--border))',
            background: 'hsl(var(--card))', color: 'hsl(var(--foreground))',
            fontSize: '0.875rem', outline: 'none',
          }}
        />
      </div>

      {/* ── Liste des offres ── */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: '60px 0', color: 'hsl(var(--muted-foreground))' }}>
          Chargement…
        </div>
      ) : filtered.length === 0 ? (
        <div className="premium-card" style={{ padding: '60px', textAlign: 'center' }}>
          <p style={{ fontSize: '2.5rem', margin: '0 0 12px' }}>📭</p>
          <h3 style={{ margin: '0 0 8px', color: 'hsl(var(--foreground))', fontSize: '1.1rem', fontWeight: 600 }}>
            {search || filter !== 'all' ? 'Aucune offre trouvée' : 'Aucune offre créée'}
          </h3>
          <p style={{ margin: '0 0 20px', color: 'hsl(var(--muted-foreground))', fontSize: '0.875rem' }}>
            {search || filter !== 'all'
              ? 'Essayez de modifier vos filtres.'
              : 'Créez votre première offre — elle apparaîtra automatiquement sur le site web.'}
          </p>
          {!search && filter === 'all' && (
            <button onClick={openCreate} style={{
              padding: '9px 22px', borderRadius: '9999px', border: 'none',
              background: 'hsl(var(--foreground))', color: 'hsl(var(--card))',
              fontSize: '0.875rem', fontWeight: 600, cursor: 'pointer',
            }}>
              + Créer une offre
            </button>
          )}
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {filtered.map((offer) => (
            <OfferCard
              key={offer.id}
              offer={offer}
              onEdit={openEdit}
              onToggle={handleToggle}
            />
          ))}
        </div>
      )}

      {/* ── Modal formulaire ── */}
      {showForm && (
        <OfferForm
          initial={editingOffer}
          onSave={handleSave}
          onCancel={closeForm}
          loading={saving}
        />
      )}
    </div>
  );
}
